import sys
sys.setrecursionlimit(10000)

def find_centroid(adj, n):
    removed = [False] * n
    subtree  = [0] * n

    def calc_size(u, parent):
        subtree[u] = 1
        for v in adj[u]:
            if v != parent and not removed[v]:
                calc_size(v, u)
                subtree[u] += subtree[v]

    def get_centroid(u, parent, tree_size):
        for v in adj[u]:
            if v != parent and not removed[v]:
                # If child's subtree > half the component, centroid is deeper
                if subtree[v] > tree_size // 2:
                    return get_centroid(v, u, tree_size)
        # No child exceeds half — check the 'upward' component too
        # upward size = tree_size - subtree[u]
        if ___________:         # if upward component also <= half
            return u
        # Otherwise centroid must be above us — caller handles this
        return get_centroid(parent, u, tree_size)  # backtrack

    calc_size(0, -1)
    return get_centroid(0, -1, subtree[0])
